class Solution {
public:
    string baseNeg2(int n) {
        if (n == 0) return "0";
        string res = "";
        while (n != 0) {
            int remainder = n % (-2);
            if (remainder < 0) {
                remainder += 2;
                n++;
            }
            res = (remainder == -2 ? "2" : (remainder == 1 ? "1" : "0")) + res;
            n /= -2;
        }
        return res;
    }
};
```
